-- Import teams data from CSV (upsert: insert new, update changed, skip identical)
ON CONFLICT ((UPPER(nomor_polisi))) WHERE nomor_polisi IS NOT NULL
DO UPDATE SET
  vendor_id = EXCLUDED.vendor_id,
  peruntukan_id = EXCLUDED.peruntukan_id,
  category = EXCLUDED.category,
  description = EXCLUDED.description
WHERE
  teams.vendor_id IS DISTINCT FROM EXCLUDED.vendor_id
  OR teams.peruntukan_id IS DISTINCT FROM EXCLUDED.peruntukan_id
  OR teams.category IS DISTINCT FROM EXCLUDED.category
  OR teams.description IS DISTINCT FROM EXCLUDED.description;